class Solution {
public:
    int repeatedStringMatch(string a, string b) {
        int count = 1;
        string temp = a;
        while (temp.length() < b.length()) {
            temp += a;
            count++;
        }
        if (temp.find(b) != string::npos) {
            return count;
        } else if (temp.length() < b.length() * 2) {
            temp += a;
            if (temp.find(b) != string::npos) {
                return count + 1;
            } else {
                return -1;
            }
        } else {
            return -1;
        }
    }
};
```

